import tracemalloc
import time
from typing import Dict, List
from dataclasses import dataclass
from contextlib import contextmanager

@dataclass
class MemoryPhase:
    """Record memory for a single phase."""
    name: str
    start_mb: float
    end_mb: float
    peak_mb: float

    @property
    def delta_mb(self) -> float:
        return self.end_mb - self.start_mb

class MemoryProfiler:
    """Profile memory usage across quantum workflow phases."""

    def __init__(self):
        self.phases: List[MemoryPhase] = []
        self._tracking = False

    def start(self):
        """Start memory tracking."""
        tracemalloc.start()
        self._tracking = True

    def stop(self):
        """Stop memory tracking."""
        if self._tracking:
            tracemalloc.stop()
            self._tracking = False

    def _get_memory_mb(self) -> tuple:
        """Get current and peak memory in MB."""
        if self._tracking:
            current, peak = tracemalloc.get_traced_memory()
            return current / (1024 * 1024), peak / (1024 * 1024)
        return 0.0, 0.0

    @contextmanager
    def phase(self, name: str):
        """Context manager to track memory for a phase."""
        start_mb, _ = self._get_memory_mb()

        # Reset peak for this phase
        tracemalloc.reset_peak()

        try:
            yield
        finally:
            end_mb, peak_mb = self._get_memory_mb()
            self.phases.append(MemoryPhase(
                name=name,
                start_mb=start_mb,
                end_mb=end_mb,
                peak_mb=peak_mb
            ))

    def get_report(self) -> Dict:
        """Generate memory report."""
        if not self.phases:
            return {'phases': [], 'total_peak_mb': 0}

        phase_data = []
        for p in self.phases:
            phase_data.append({
                'name': p.name,
                'start_mb': round(p.start_mb, 2),
                'end_mb': round(p.end_mb, 2),
                'delta_mb': round(p.delta_mb, 2),
                'peak_mb': round(p.peak_mb, 2)
            })

        return {
            'phases': phase_data,
            'total_peak_mb': round(max(p.peak_mb for p in self.phases), 2),
            'final_memory_mb': round(self.phases[-1].end_mb, 2)
        }


# Test the profiler
if __name__ == "__main__":
    import numpy as np

    profiler = MemoryProfiler()
    profiler.start()

    with profiler.phase("array_creation"):
        arr = np.zeros((2**20,), dtype=np.complex128)

    with profiler.phase("computation"):
        result = np.abs(arr) ** 2

    with profiler.phase("cleanup"):
        del arr, result

    report = profiler.get_report()
    print("Memory Profile Report:")
    for phase in report['phases']:
        print(f"  {phase['name']}: {phase['delta_mb']:+.2f} MB (peak: {phase['peak_mb']:.2f} MB)")
    print(f"Total Peak: {report['total_peak_mb']:.2f} MB")
    profiler.stop()
